cat > /tmp/repro_sqlite_nodatime_ef10.sh <<'EOF'
#!/usr/bin/env bash
repo="/workspace/EFCorePowerTools"
work="/tmp/efcpt-sqlite-nodatime-repro"
rm -rf "$work"
mkdir -p "$work"
cat > "$work/Repro.csproj" <<'XML'
<Project Sdk="Microsoft.NET.Sdk">
  <PropertyGroup>
    <OutputType>Exe</OutputType>
    <TargetFramework>net10.0</TargetFramework>
    <ImplicitUsings>enable</ImplicitUsings>
    <Nullable>enable</Nullable>
  </PropertyGroup>
  <ItemGroup>
    <ProjectReference Include="/workspace/EFCorePowerTools/src/GUI/RevEng.Shared/RevEng.Common.csproj" />
  </ItemGroup>
</Project>
XML
cat > "$work/Program.cs" <<'CS'
using RevEng.Common;

static void AssertSqliteNodaTime(CodeGenerationMode mode, string expectedVersion)
{
    var packages = Providers.GetNeededPackages(
        DatabaseType.SQLite,
        useSpatial: false,
        useNodaTime: true,
        useDateOnlyTimeOnly: false,
        useHierarchyId: false,
        discoverMultipleResultSets: false,
        hasProcedures: false,
        codeGenerationMode: mode);

    var sqliteNodaTime = packages.SingleOrDefault(p => p.PackageId == "EntityFrameworkCore.Sqlite.NodaTime");
    if (sqliteNodaTime?.Version != expectedVersion)
    {
        throw new InvalidOperationException($"{mode}: expected EntityFrameworkCore.Sqlite.NodaTime {expectedVersion}, got '{sqliteNodaTime?.Version ?? "<missing>"}'.");
    }
}

AssertSqliteNodaTime(CodeGenerationMode.EFCore8, "8.0.0");
AssertSqliteNodaTime(CodeGenerationMode.EFCore9, "9.1.0");
AssertSqliteNodaTime(CodeGenerationMode.EFCore10, "10.0.0");

var noNodaTime = Providers.GetNeededPackages(
    DatabaseType.SQLite,
    useSpatial: false,
    useNodaTime: false,
    useDateOnlyTimeOnly: false,
    useHierarchyId: false,
    discoverMultipleResultSets: false,
    hasProcedures: false,
    codeGenerationMode: CodeGenerationMode.EFCore10);

if (noNodaTime.Any(p => p.PackageId == "EntityFrameworkCore.Sqlite.NodaTime"))
{
    throw new InvalidOperationException("SQLite NodaTime package should only be included when useNodaTime is true.");
}

Console.WriteLine("Provider package selection supports SQLite NodaTime for EF Core 8, 9, and 10.");
CS
cd "$work" || exit 1
dotnet run --verbosity quiet

grep -q '<PackageReference Include="EntityFrameworkCore.Sqlite.NodaTime" Version="10.0.0" />' "$repo/src/Core/RevEng.Core.100/RevEng.Core.100.csproj"
grep -q 'new SqliteNodaTimeDesignTimeServices()' "$repo/src/Core/RevEng.Core.80/ServiceProviderBuilder.cs"
if sed -n '/case DatabaseType.SQLite:/,/break;/p' "$repo/src/Core/RevEng.Core.80/ServiceProviderBuilder.cs" | grep -q 'CORE100'; then
  echo "SQLite service registration should not exclude CORE100." >&2
  exit 3
fi

echo "EF Core 10 project and service-provider checks passed."
EOF
chmod +x /tmp/repro_sqlite_nodatime_ef10.sh
/tmp/repro_sqlite_nodatime_ef10.sh

